import{_ as a,o as t,c as o,ae as s}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"SKAdNetwork Agency Permissions","description":"","frontmatter":{"title":"SKAdNetwork Agency Permissions","slug":"skadnetwork-agency-permissions"},"headers":[],"relativePath":"marketer-hub/skadnetwork-agency-permissions.md","filePath":"marketer-hub/skadnetwork-agency-permissions.md"}'),i={name:"marketer-hub/skadnetwork-agency-permissions.md"};function r(n,e,c,d,l,h){return t(),o("div",null,[...e[0]||(e[0]=[s('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Special agency access to the Branch Dashboard allows teams to provide specific permissions and access rights to activated agencies. With the introduction of SKAdNetwork, agencies with the following data filters could not view SKAdNetwork data on the Branch Dashboard:</p><ul><li>Agency-tagged data</li><li>Revenue data</li><li>Location data</li></ul><p>Special SKAdNetwork agency permissions gives you <strong>more flexibility</strong> on what SKAdNetwork data to share with agencies. This allows agencies to better understand their campaign performance across networks and to take action based on those insights.</p><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><p>For every enabled ad partner and campaign, you can set up individual agency permissions for accessing SKAdNetwork data. This will be decoupled from the agencies&#39; app-level permissions.</p><h2 id="implementation" tabindex="-1">Implementation <a class="header-anchor" href="#implementation" aria-label="Permalink to &quot;Implementation&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Prerequisites</p><ol><li><a href="./add-agency-to-your-account.html">Agency access is already set up</a> for your Branch Dashboard</li><li><a href="./add-manage-users-roles-permissions-access.html">Admin</a> access to your Branch Dashboard</li></ol></div><ol><li>In the Branch Dashboard, navigate to the Agency Permissions in the <a href="https://dashboard.branch.io/ads/skadnetwork/configuration" target="_blank" rel="noreferrer">SKAdNetwork Configuration</a><br> a. Ads → SKAdNetwork → Configuration Tab → Agency Permissions</li><li>Select &quot;Add New Agency Permission&quot;</li><li>Set up permissions<br> a. Select Agency<br> b. Select Ad Partner<br> c. Select the campaigns that the agency should have access to for that ad partner (or select all)<br> d. Click &quot;Save&quot;<br> e. Repeat process for additional permissions.</li><li>Remove or edit permissions as needed.</li></ol>',9)])])}const g=a(i,[["render",r]]);export{p as __pageData,g as default};
